/**
 * Auto-generated lesson manifest for language-shona.
 *
 * Source-of-truth lives in Supabase Storage at:
 *   course-content/lessons/language-shona/<speakerId>/<lessonId>.json
 *
 * This manifest carries ONLY the metadata the Learn tab needs to render
 * the unit list (id, module, lesson, title, xpReward) so we don't have
 * to bundle every lesson's full content in the JS binary.
 *
 * Regenerate with:  npx tsx scripts/generate-manifests-from-storage.ts
 *
 * DO NOT EDIT BY HAND.
 */

export interface LessonMeta {
  id: string;
  module: number;
  lesson: number;
  title: string;
  xpReward: number;
  /** Content version for cache invalidation. Bump when re-authoring a lesson;
   *  loader compares cached vs manifest version and refetches on mismatch.
   *  Default: 1 (treated as the initial author). */
  version?: number;
}

